mapper.select:
SELECT br.*, r.id AS r_id, r.name AS r_name, c.id AS c_id, c.name AS c_name FROM bus_route br LEFT JOIN region r ON br.region_id = r.id LEFT JOIN company c ON br.company_id = c.id WHERE 1 = 1
AND br.region_id = #{regionId}
AND br.company_id = #{companyId}
AND br.route_type = #{routeType}
AND br.is_active = #{isActive}
AND MATCH(br.route_number, br.route_name, br.start_stop, br.end_stop, br.down_start_stop, br.down_end_stop) AGAINST(#{keyword} IN BOOLEAN MODE)
ORDER BY br.route_number ASC, br.sub_type ASC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1) FROM bus_route br
WHERE 1 = 1

    AND br.region_id = #{regionId}


    AND br.company_id = #{companyId}


    AND br.route_type = #{routeType}


    AND br.is_active = #{isActive}


    AND MATCH(br.route_number, br.route_name, br.start_stop, br.end_stop,
             br.down_start_stop, br.down_end_stop)
        AGAINST(#{keyword} IN BOOLEAN MODE)
